import React, { useEffect, useState } from "react";

interface Note {
  id: string;
  title: string;
  content: string;
  image?: string;
  pinned?: boolean;
  createdAt: number;
}

const SAMPLE_IMAGES = {
  trex: "https://www.lamontagneart.com/wp-content/uploads/2021/01/LaMontagne_TRex01.jpg",
  brachiosaurus: "https://lookaside.fbsbx.com/lookaside/crawler/media/?media_id=1212376492461191",
  triceratops: "https://c8.alamy.com/comp/2MN926H/triceratops-dinosaur-horridus-face-close-up-with-yellow-eyes-2MN926H.jpg",
  velociraptor: "https://i.ytimg.com/vi/mP93YcbQfeg/maxresdefault.jpg"
};

const initialNotes = (): Note[] => {
  const stored = localStorage.getItem("dino_notes_v1");
  if (stored) {
    try {
      return JSON.parse(stored) as Note[];
    } catch (e) {
      console.warn("Could not parse stored notes, resetting.");
    }
  }
  const now = Date.now();
  return [
    {
      id: "1",
      title: "Tyrannosaurus Rex - King of the Cretaceous",
      content: "Powerful predator with massive jaws. A classic T. rex portrait sample.",
      image: SAMPLE_IMAGES.trex,
      pinned: true,
      createdAt: now - 1000 * 60 * 60 * 24 * 3
    },
    {
      id: "2",
      title: "Brachiosaurus Grazing",
      content: "A long-neck giant nibbling leaves from the treetops.",
      image: SAMPLE_IMAGES.brachiosaurus,
      createdAt: now - 1000 * 60 * 60 * 24 * 2
    },
    {
      id: "3",
      title: "Triceratops Closeup",
      content: "A horned herbivore captured in a close portrait.",
      image: SAMPLE_IMAGES.triceratops,
      createdAt: now - 1000 * 60 * 60 * 24
    },
    {
      id: "4",
      title: "Velociraptor in Motion",
      content: "Swift and agile hunter - sample action frame.",
      image: SAMPLE_IMAGES.velociraptor,
      createdAt: now
    }
  ];
};

export default function App(): JSX.Element {
  const [notes, setNotes] = useState<Note[]>(initialNotes);
  const [title, setTitle] = useState("");
  const [content, setContent] = useState("");
  const [image, setImage] = useState("");
  const [query, setQuery] = useState("");

  useEffect(() => {
    localStorage.setItem("dino_notes_v1", JSON.stringify(notes));
  }, [notes]);

  const addNote = () => {
    if (!title.trim() && !content.trim() && !image.trim()) return;
    const newNote: Note = {
      id: String(Date.now()),
      title: title.trim() || "Untitled",
      content: content.trim(),
      image: image.trim() || undefined,
      pinned: false,
      createdAt: Date.now()
    };
    setNotes([newNote, ...notes]);
    setTitle("");
    setContent("");
    setImage("");
  };

  const removeNote = (id: string) => {
    if (!confirm("Delete this note?")) return;
    setNotes(notes.filter((n) => n.id !== id));
  };

  const togglePin = (id: string) => {
    setNotes(
      notes.map((n) => (n.id === id ? { ...n, pinned: !n.pinned } : n)).sort((a, b) => {
        // pinned first, then newest
        if ((a.pinned ? 1 : 0) !== (b.pinned ? 1 : 0)) return (b.pinned ? 1 : 0) - (a.pinned ? 1 : 0);
        return b.createdAt - a.createdAt;
      })
    );
  };

  const editNote = (id: string) => {
    const note = notes.find((n) => n.id === id);
    if (!note) return;
    const newTitle = prompt("Edit title", note.title) ?? note.title;
    const newContent = prompt("Edit content", note.content) ?? note.content;
    const newImage = prompt("Edit image URL (leave blank to remove)", note.image ?? "") ?? note.image;
    setNotes(notes.map((n) => (n.id === id ? { ...n, title: newTitle, content: newContent, image: newImage || undefined } : n)));
  };

  const clearAll = () => {
    if (!confirm("Clear all notes?")) return;
    setNotes([]);
  };

  const searchSample = (key: keyof typeof SAMPLE_IMAGES) => {
    // quick helper to populate image field with a sample image
    setImage(SAMPLE_IMAGES[key]);
  };

  const filtered = notes.filter((n) => {
    if (!query.trim()) return true;
    const q = query.toLowerCase();
    return (n.title + " " + n.content).toLowerCase().includes(q);
  });

  return (
    <div style={styles.app}>
      <header style={styles.header}>
        <h1 style={{ margin: 0 }}>Dino Notes</h1>
        <p style={{ margin: 0, opacity: 0.8 }}>A simple notes app with dinosaur sample photos</p>
      </header>

      <section style={styles.controls}>
        <div style={styles.inputRow}>
          <input
            style={styles.input}
            placeholder="Title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />
          <input
            style={styles.input}
            placeholder="Image URL (or use sample below)"
            value={image}
            onChange={(e) => setImage(e.target.value)}
          />
        </div>
        <textarea
          style={styles.textarea}
          placeholder="Write your note here..."
          value={content}
          onChange={(e) => setContent(e.target.value)}
        />
        <div style={styles.rowBetween}>
          <div style={{ display: "flex", gap: 8 }}>
            <button style={styles.buttonPrimary} onClick={addNote}>
              Add Note
            </button>
            <button
              style={styles.button}
              onClick={() => {
                setTitle("");
                setContent("");
                setImage("");
              }}
            >
              Clear
            </button>
            <button style={styles.buttonDanger} onClick={clearAll}>
              Clear All Notes
            </button>
          </div>

          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <input
              style={{ ...styles.input, width: 200 }}
              placeholder="Search notes..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
            />
            <span style={{ fontSize: 12, opacity: 0.8 }}>Samples:</span>
            <button style={styles.pill} onClick={() => searchSample("trex")}>T. rex</button>
            <button style={styles.pill} onClick={() => searchSample("brachiosaurus")}>Brachiosaurus</button>
            <button style={styles.pill} onClick={() => searchSample("triceratops")}>Triceratops</button>
            <button style={styles.pill} onClick={() => searchSample("velociraptor")}>Velociraptor</button>
          </div>
        </div>
      </section>

      <main style={styles.grid}>
        {filtered.length === 0 ? (
          <div style={styles.empty}>No notes found — add one to get started.</div>
        ) : (
          filtered.map((note) => (
            <article key={note.id} style={{ ...styles.card, boxShadow: note.pinned ? "0 6px 18px rgba(0,0,0,0.18)" : undefined }}>
              <div style={styles.cardHeader}>
                <h3 style={{ margin: 0 }}>{note.title}</h3>
                <div style={{ display: "flex", gap: 8 }}>
                  <button title="Pin" onClick={() => togglePin(note.id)} style={styles.iconButton}>
                    {note.pinned ? "📌" : "📍"}
                  </button>
                  <button title="Edit" onClick={() => editNote(note.id)} style={styles.iconButton}>✏️</button>
                  <button title="Delete" onClick={() => removeNote(note.id)} style={styles.iconButton}>🗑️</button>
                </div>
              </div>

              {note.image ? (
                <div style={styles.imageWrap}>
                  <img src={note.image} alt={note.title} style={styles.image} onError={(e) => {
                    // hide broken images
                    (e.target as HTMLImageElement).style.display = "none";
                  }} />
                </div>
              ) : null}

              <p style={styles.content}>{note.content}</p>

              <footer style={styles.cardFooter}>
                <small style={{ color: "#666" }}>{new Date(note.createdAt).toLocaleString()}</small>
              </footer>
            </article>
          ))
        )}
      </main>

      <footer style={styles.footer}>Made with 🦖 — sample images are embedded from external sources.</footer>
    </div>
  );
}

